import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { IncomeItem, IncomeKind } from '../../../core/models';
import { formatCents, toCents } from '../../../core/money';

/** Wizard step 3 — add/remove income items (W-2, interest, self-employment). */
@Component({
  selector: 'app-income',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './income.component.html',
  styleUrl: './income.component.css',
})
export class IncomeComponent {
  returnId = '';

  // Mock data — service_agent clears this and loads via ApiService.listIncome().
  income = signal<IncomeItem[]>([
    { id: 'i1', returnId: 'r-2024', kind: 'w2', payer: 'Northwind LLC', amountCents: 6850000, withheldCents: 780000 },
  ]);

  readonly kinds: { value: IncomeKind; label: string }[] = [
    { value: 'w2', label: 'W-2 wages' },
    { value: 'int', label: 'Interest (1099-INT)' },
    { value: 'nec', label: 'Self-employment (1099-NEC)' },
  ];

  readonly kindLabels: Record<IncomeKind, string> = {
    w2: 'W-2 wages',
    int: 'Interest',
    nec: 'Self-employment',
  };

  newKind: IncomeKind = 'w2';
  newPayer = '';
  newAmount: number | null = null;
  newWithheld: number | null = null;

  fmt = formatCents;

  constructor(private route: ActivatedRoute, private router: Router) {
    this.returnId = this.route.parent?.snapshot.paramMap.get('id') ?? '';
  }

  totalCents(): number {
    return this.income().reduce((sum, i) => sum + i.amountCents, 0);
  }

  add(): void {
    if (!this.newPayer || this.newAmount === null) return;
    this.income.update((list) => [
      ...list,
      {
        id: 'i' + (list.length + 1),
        returnId: this.returnId,
        kind: this.newKind,
        payer: this.newPayer,
        amountCents: toCents(this.newAmount ?? 0),
        withheldCents: this.newKind === 'w2' ? toCents(this.newWithheld ?? 0) : null,
      },
    ]);
    this.newPayer = '';
    this.newAmount = null;
    this.newWithheld = null;
  }

  remove(id: string): void {
    this.income.update((list) => list.filter((i) => i.id !== id));
  }

  back(): void {
    this.router.navigate(['/returns', this.returnId, 'wizard', 'dependents']);
  }

  next(): void {
    this.router.navigate(['/returns', this.returnId, 'wizard', 'deductions']);
  }
}
